import React from "react";
import ReactDOM from "react-dom";
import "./nav.css";

function Nav() {
  function Modal() {
    const Modal = (props) => {
      return ReactDOM.createPortal(
        <div className="pushMenu">{props.children}</div>,
        modalRoot
      );
    };
  }
  const [open, setOpen] = React.useState(false);
  return <div onClick={Modal} className="gg-menu-grid-o"></div>;
}

export default Nav;

